INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-d35ec6db-moex-00107', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲將收藏多年價值新臺幣（下同）60萬元之古董花瓶委託乙清潔上釉，未料乙竟將此花瓶整理後 用自己名義以80萬元出售給收藏家丙後，將價金拿去酒店花光。下列敘述，何者正確？ 甲得向乙主張不法管理，請其返還80萬元 甲得向乙主張成立侵權行為，請求乙賠償80萬元，並得請求精神慰撫金 甲得向乙主張不當得利，請乙返還80萬元。但因利益已花完，故已無須返還 甲得主張乙無權代理，請求乙返還80萬元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00108', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '以所有之意思，二十年間和平、公然、繼續占有他人未登記之不動產者，關於其法律效果，下列 敘述，何者正確？ 立即取得該不動產之所有權  得請求登記為不動產所有人 得向法院訴請判決為所有人  得請求該他人協同辦理登記', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00109', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '不動產抵押權，乃以不動產為標的物之擔保物權。下列何者非不動產抵押權效力所及？ 以建築物為抵押者，於抵押權設定後附加於建築物，具有獨立性之物 抵押物滅失之殘餘物 抵押物之從物 抵押物扣押後自抵押物分離，而得由抵押人收取之天然孳息', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00110', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲乙丙丁四人為A地分別共有人，就A地之使用訂立分管契約。嗣後，甲將其A地應有部分讓 與戊。關於分管契約之拘束力，下列敘述，何者正確？ 不論戊是否知悉，分管契約對於戊均有拘束力 戊明知分管契約時，分管契約始對戊有拘束力 分管契約於登記後，對於受讓人戊始有拘束力 分管契約是債權契約，絕不可能對戊生拘束力', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00111', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲、乙與丙登記為A地之公同共有人。關於公同共有人之權利，下列敘述，何者正確？ 甲得自由處分A地 甲得自由處分其應有部分 甲得隨時請求分割A地 丁無權占有A地。甲得以自己名義，請求丁返還A地於全體', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00112', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '稱不動產物權行為者，謂以不動產物權變動為直接內容之法律行為。關於不動產物權行為，下列 敘述，何者錯誤？ 不動產物權行為是不要物行為 不動產物權行為以登記為生效要件 不動產物權行為應以書面為之 不動產物權行為，非經公證人作成公證書，不生效力', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00113', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲男乙女於民國110年2月14日結婚。甲乙未約定夫妻財產制，乙於婚後無勞力所得，專心在 家操持家務。關於婚姻普通效力及夫妻財產之規定，下列敘述，何者正確？ 甲乙對於其婚前財產，互負報告之義務。於家庭生活費用外，甲乙應協議一定數額之金錢，供 乙自由處分 甲如依法應給付家庭生活費用而不給付時，法院因乙之請求，得宣告改用分別財產制 甲乙之住所，由雙方共同協議之；未為協議或協議不成時，於戶政事務所抽籤決定之 甲乙係以聯合財產制為其法定夫妻財產制，財產應共同管理、使用及收益', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00114', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '40歲之養父甲與17歲之養子乙，合意終止收養關係。其收養關係自何時終止？ 合意時    書面成立時 法院認可裁定確定時  法定代理人同意時', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00115', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲為未成年人，與父乙、母丙、姊丁（已成年）共同居住於臺北市。乙之父戊居住於花蓮。某日 乙、丙遭遇車禍，同時死亡。下列何者為甲之監護人？ 法院選定之人  戊  丁  臺北市社會局', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00116', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲男中年喪偶。甲有二子乙、丙、一女丁；乙與丙均未婚。丁已婚，丁夫為戊，丁戊有一子為庚。 丁於民國（下同）111年1月間死亡。甲於111年12月間死亡。甲未立遺囑。甲有遺產新臺幣（下 同）1200萬元，無債務。關於甲遺產之繼承，下列敘述，何者正確？ 乙繼承400萬元  丙繼承300萬元  庚繼承200萬元  戊繼承150萬元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
